ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
CHOICE vague {
  component: { SELECT (AVG(?rev) AS ?avg) ?om WHERE { ?o a :Operations ; p:OperationID ?oid ; p:OperationMonths ?om ; p:Revenue ?rev } GROUP BY ?oid ?om }
  full: { SELECT (AVG(?rev) AS ?avg) ?oy ?om WHERE { ?o a :Operations ; p:OperationID ?oid ; p:OperationYears ?oy ; p:OperationMonths ?om ; p:Revenue ?rev } GROUP BY ?oid ?oy ?om }
  component_2: { SELECT (AVG(?rev) AS ?avg) ?oy WHERE { ?o a :Operations ; p:OperationID ?oid ; p:OperationYears ?oy ; p:Revenue ?rev } GROUP BY ?oid ?oy }
}

PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?operationid ?calc ?operationyears WHERE {
  ?operations a :Operations .
  ?operations p:OperationID ?operationid .
  ?operations p:Revenue ?revenue_n .
  ?operations p:Expenses ?expenses_n .
  BIND(((xsd:double(?revenue_n) - xsd:double(?expenses_n))) AS ?calc)
  ?operations p:OperationYears ?operationyears .
} }
  component_2: { SELECT ?operationid ?calc ?operationmonths WHERE {
  ?operations a :Operations .
  ?operations p:OperationID ?operationid .
  ?operations p:Revenue ?revenue_n .
  ?operations p:Expenses ?expenses_n .
  BIND(((xsd:double(?revenue_n) - xsd:double(?expenses_n))) AS ?calc)
  ?operations p:OperationMonths ?operationmonths .
} }
  full: { SELECT ?operationid ?calc ?operationyears ?operationmonths WHERE {
  ?operations a :Operations .
  ?operations p:OperationID ?operationid .
  ?operations p:Revenue ?revenue_n .
  ?operations p:Expenses ?expenses_n .
  BIND(((xsd:double(?revenue_n) - xsd:double(?expenses_n))) AS ?calc)
  ?operations p:OperationYears ?operationyears .
  ?operations p:OperationMonths ?operationmonths .
} }
}
